import React from "react";
import {ConfirmDialog} from "primereact/confirmdialog";
import {Button, Text} from "../../_compat";
import type {IConfirmDialogProps} from "@lmb-it/kitsconcerto-types";
import {useSeverityColors} from "../../hooks/useSeverityColors";
import {useKitsTheme} from "../../contexts/Theme";

export default function KitsConfirm(props: IConfirmDialogProps) {
    const {
        visible = true,
        defaultUI,
        headless,
        type = "secondary",
        icon:IconN,
        message,
        onHide,
        accept,
        reject,
        acceptLabel,
        rejectLabel,
        acceptIcon,
        rejectIcon,
        acceptClassName,
        rejectClassName,
        buttons,
        async: asyncMode,
        children,
        appendTo,
        ...rest
    } = props;

    const colors = useSeverityColors(type);
    const {resolveToken, theme} = useKitsTheme();
    const surfaceColor = resolveToken('surface-card');
    const brandLogo = type === 'brand' ? theme.config.logo : null;

    const buildBody = () =>
        ({
             headerRef,
             contentRef,
             footerRef,
             hide,
             message: msg,
         }: any) => {
            const realHeader = msg?.header ?? "";
            const realMessage = msg?.message ?? message;

            const doClick = async (
                callback: (() => void) | undefined,
                e: any
            ) => {
                if (asyncMode) {
                    await callback?.();
                    hide(e);
                } else {
                    hide(e);
                    callback?.();
                }
            };

            return (
                <div
                    className="flex flex-column align-items-center p-5 relative w-full"
                    style={{
                        backgroundColor: surfaceColor,
                        ...(type !== 'secondary' && {
                            background: `linear-gradient(${colors.bgTint} 0%, ${surfaceColor} 40%)`,
                        }),
                        borderRadius: 16,
                        boxShadow: '0 25px 50px -12px rgba(0,0,0,0.25)',
                        maxWidth: 420,
                    }}
                >
                    {/* Soft-circle icon */}
                    {headless && (IconN || brandLogo) && (
                        <div
                            style={{
                                width: 80,
                                height: 80,
                                borderRadius: 40,
                                backgroundColor: colors.iconBg,
                                display: 'flex',
                                justifyContent: 'center',
                                alignItems: 'center',
                                marginTop: -40,
                                boxShadow: '0 4px 12px rgba(0,0,0,0.1)',
                            }}
                        >
                            {brandLogo ? brandLogo : typeof IconN === "string" ? (
                                <i className={IconN} style={{fontSize: '2rem', color: colors.iconFg}}/>
                            ) : IconN}
                        </div>
                    )}

                    {/* Close button */}
                    <Button
                        icon="pi pi-times"
                        className="absolute top-0 right-0 mr-2 mt-2 w-2rem h-2rem"
                        severity="secondary"
                        outlined
                        onClick={(e) => hide(e)}
                    />

                    {/* HEADER */}
                    <span
                        ref={headerRef}
                        className="font-bold text-2xl block mt-3 mb-2 text-center w-full"
                    >
                        {realHeader}
                    </span>

                    {/* MESSAGE */}
                    <Text
                        ref={contentRef}
                        as="p"
                        className="text-color text-center"
                        style={{width: "100%"}}
                    >
                        {realMessage}
                    </Text>

                    {/* FOOTER */}
                    <div
                        ref={footerRef}
                        className="flex align-items-center gap-2 mt-5 w-full justify-content-center flex-wrap"
                    >
                        {buttons?.length ? (
                            buttons.map((b, i) => (
                                <Button
                                    key={i}
                                    label={b.title}
                                    outlined={b.outlined}
                                    rounded={b.rounded}
                                    severity={b.type ?? type}
                                    disabled={b.disabled}
                                    loading={b.loading}
                                    style={{
                                        borderRadius: b.rounded ? 9999 : undefined,
                                    }}
                                    className="min-w-7rem"
                                    onClick={() =>
                                        b.onClick(hide, accept, reject)
                                    }
                                />
                            ))
                        ) : (
                            <>
                                <Button
                                    label={acceptLabel ?? "Accept"}
                                    icon={acceptIcon as any}
                                    severity={type}
                                    className={`min-w-7rem ${acceptClassName ?? ""}`}
                                    onClick={(e) => doClick(accept, e)}
                                />

                                <Button
                                    label={rejectLabel ?? "Reject"}
                                    icon={rejectIcon as any}
                                    outlined
                                    severity={type}
                                    className={`min-w-7rem ${rejectClassName ?? ""}`}
                                    onClick={(e) => doClick(reject, e)}
                                />
                            </>
                        )}
                    </div>
                </div>
            );
        };

    if (defaultUI) {
        return (
            // @ts-ignore
            <ConfirmDialog
                {...rest}
                visible={visible}
                onHide={onHide}
                accept={accept}
                reject={reject}
                message={message}
                icon={typeof IconN === 'string' ? IconN : undefined}
                acceptLabel={acceptLabel}
                rejectLabel={rejectLabel}
                acceptIcon={acceptIcon}
                rejectIcon={rejectIcon}
                acceptClassName={acceptClassName}
                rejectClassName={rejectClassName}
                className={`kits-confirm-dialog kits-confirm-${type}`}
            />
        );
    }

    const renderedContent = children ?? buildBody();

    return (
        // @ts-ignore
        <ConfirmDialog
            {...rest}
            visible={visible}
            onHide={onHide}
            accept={accept}
            reject={reject}
            content={renderedContent}
            className={`kits-confirm-dialog kits-confirm-${type}`}
        />
    );
}
